// n8n Code node (Run once for all items)
// Sortie: [{ json: { subject, html, text } }]

'use strict';

// ---------- Helpers ----------
const nf = new Intl.NumberFormat('fr-FR');
const n0 = (v) => {
  const num = Number(v);
  return nf.format(Number.isFinite(num) ? num : 0);
};
const esc = (s) =>
  String(s ?? '').replace(/[&<>"']/g, (c) => (
    { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]
  ));
const isObj = (x) => x && typeof x === 'object' && !Array.isArray(x);

function fmtDate(x) {
  if (x == null) return '—';
  if (typeof x === 'string') return x;
  if (typeof x === 'number') {
    try { return new Date(x).toISOString().slice(0, 10); } catch { return String(x); }
  }
  if (isObj(x)) {
    const keys = ['iso', 'value', 'date', 'start', 'end'];
    for (const k of keys) if (x[k]) return String(x[k]);
    return '—';
  }
  return '—';
}

// Récupérer la donnée source
function getData(items) {
  for (const it of items) {
    const j = it?.json;
    if (isObj(j) && (j.accounts || j.global_metrics || j.stockVivant)) return j;
  }
  return items?.[0]?.json ?? {};
}

const data = getData(items);

// ---------- Dates / période ----------
const dateSelected = data.date_selected || data.period_info?.selected_date || '—';

// ---------- Partie 1 : Dépenses (jour / semaine / mois) ----------
let totalDay = 0, totalWeek = 0, totalMonth = 0;
const perAccountTotals = []; // [{account, group, weekly, monthly}]

// Dépenses du jour pour TOUS les comptes (≠ 0)
const allDailyHTMLRows = [];
const allDailyTextRows = [];

if (isObj(data.accounts)) {
  for (const [groupName, groupObj] of Object.entries(data.accounts)) {
    if (!isObj(groupObj)) continue;

    for (const [accName, accData] of Object.entries(groupObj)) {
      if (!isObj(accData)) continue;

      const dayExp   = Number(accData.dailyExpenses?.total_daily_expenses || 0);
      const weekExp  = Number(accData.weeklyExpenses?.total_weekly_expenses || 0);
      const monthExp = Number(accData.monthlyExpenses?.total_monthly_expenses || 0);

      totalDay  += dayExp;
      totalWeek += weekExp;
      totalMonth+= monthExp;

      perAccountTotals.push({
        account: accName,
        group: accData.accountInfo?.type || groupName,
        weekly: weekExp,
        monthly: monthExp,
      });

      // Lister les écritures uniquement si total du jour ≠ 0
      if (dayExp !== 0) {
        const list = Array.isArray(accData.dailyExpenses?.expenses)
          ? accData.dailyExpenses.expenses
          : [];

        if (list.length > 0) {
          for (const e of list) {
            const amount = Number(e?.amount || 0);
            if (!Number.isFinite(amount)) continue;

            allDailyHTMLRows.push([
              esc(accName),
              esc(e?.description ?? ''),
              esc(e?.supplier ?? ''),
              n0(amount),
              esc(e?.category ?? ''),
              esc(e?.subcategory ?? ''),
              esc(e?.type ?? ''),
            ]);
            allDailyTextRows.push([
              String(accName),
              String(e?.description ?? ''),
              String(e?.supplier ?? ''),
              n0(amount),
              String(e?.category ?? ''),
              String(e?.subcategory ?? ''),
              String(e?.type ?? ''),
            ]);
          }
        } else {
          // Total ≠ 0 mais pas de détails disponibles
          allDailyHTMLRows.push([
            esc(accName),
            '— (détails indisponibles)',
            '—',
            n0(dayExp),
            '—',
            '—',
            '—',
          ]);
          allDailyTextRows.push([
            String(accName),
            '— (détails indisponibles)',
            '—',
            n0(dayExp),
            '—',
            '—',
            '—',
          ]);
        }
      }
    }
  }
}

// ---------- Partie 2 : Stock vivant (delta + produits) ----------
const sv = data.stockVivant || {};
const delta = sv.delta || {};
const deltaView = {
  previous_total: (delta.previous_total ?? null),
  current_total:  (delta.current_total ?? null),
  difference:     (delta.difference ?? (
    delta.current_total != null && delta.previous_total != null
      ? (Number(delta.current_total) - Number(delta.previous_total))
      : null
  )),
  percentage_change: (delta.percentage_change != null)
    ? Number(delta.percentage_change)
    : (delta.current_total != null && delta.previous_total
        ? ((Number(delta.current_total) - Number(delta.previous_total)) / (Number(delta.previous_total) || 1)) * 100
        : null)
};

// Liste par produit depuis delta.product_changes
const productChanges =
  Array.isArray(delta.product_changes) ? delta.product_changes :
  Array.isArray(delta.productChanges) ? delta.productChanges :
  Array.isArray(sv.product_changes)   ? sv.product_changes   : [];

// ---------- Partie 3 : stockSoirMata ----------
const ssm = data.stockSoirMata || {};
const ssmTotalValue = ssm.total_value ?? null;

// Somme par point_de_vente à partir de entries[].stock_soir
const byPdV = {};
if (Array.isArray(ssm.entries)) {
  for (const entry of ssm.entries) {
    const pdv = entry.point_de_vente || entry.pointDeVente || entry.pdv || 'Non spécifié';
    const v = Number(entry.stock_soir || 0);
    byPdV[pdv] = (byPdV[pdv] || 0) + (Number.isFinite(v) ? v : 0);
  }
}

// ---------- Partie 4 : livraisonPartenaire ----------
const lp = data.livraisonPartenaire || data.deliveriesPartenaire || {};
const livraisonRows = []; // { partner, date, amount, description, status, total_validated_deliveries, remaining_balance }

function pushRow(partnerName, obj) {
  livraisonRows.push({
    partner: partnerName || obj.partner || '—',
    date: fmtDate(obj.latest_delivery?.date || obj.date),
    amount: Number(obj.latest_delivery?.amount ?? obj.amount ?? 0),
    description: obj.latest_delivery?.description ?? obj.description ?? '',
    status: obj.latest_delivery?.status ?? obj.status ?? '',
    total_validated_deliveries: Number(obj.total_validated_deliveries ?? 0),
    remaining_balance: Number(obj.remaining_balance ?? 0),
  });
}
if (isObj(lp)) {
  for (const [name, obj] of Object.entries(lp)) {
    if (isObj(obj)) pushRow(name, obj);
  }
}

// ---------- Partie 5 : global_metrics (PL uniquement) ----------
const gm = data.global_metrics || {};
const pnl = gm.profitAndLoss || gm.profit_and_loss || {};
const brutPLObj = pnl.brutPL || gm.brutPL || {};
const brutComp  = brutPLObj.components || {};

const estPLObj  = pnl.estimatedProfitAndLoss || gm.estimatedProfitAndLoss || {};
const estComp   = estPLObj.components || {};
const fixedCharges = (estComp.estimated_fixed_charges != null)
  ? estComp.estimated_fixed_charges
  : estComp.charges_prorata; // fallback éventuel

// ---------- HTML helpers ----------
function table(headers, rows) {
  const thead = `<thead><tr>${headers.map(h=>`<th style="text-align:left;padding:6px;border-bottom:1px solid #ddd;">${esc(h)}</th>`).join('')}</tr></thead>`;
  const tbody = `<tbody>${rows.map(r=>`<tr>${r.map(c=>`<td style="padding:6px;border-bottom:1px solid #f0f0f0;">${c}</td>`).join('')}</tr>`).join('')}</tbody>`;
  return `<table style="border-collapse:collapse;width:100%;margin:6px 0 12px 0;">${thead}${tbody}</table>`;
}
const h1 = (t)=>`<h2 style="margin:14px 0 8px 0;font-family:Arial;">${esc(t)}</h2>`;
const p  = (t)=>`<p style="margin:6px 0;font-family:Arial;">${esc(t)}</p>`;

// Lignes pré-calculées
const dateLine = p('Date : ' + esc(dateSelected));
const ssmLine  = p('Valeur totale (stockSoirMata.total_value) : ' + (ssmTotalValue == null ? '—' : n0(ssmTotalValue)));

// ----- Partie 1 (HTML) -----
const part1Header = table(
  ['Dépenses du jour', 'Semaine', 'Mois'],
  [[n0(totalDay), n0(totalWeek), n0(totalMonth)]]
);

// Dépenses du jour (≠ 0) – tous comptes (section visible seulement si lignes)
const part1DailyTitle = allDailyHTMLRows.length ? p('Dépenses du jour (≠ 0) – tous comptes') : '';
const part1DailyTable = allDailyHTMLRows.length
  ? table(
      ['Compte', 'Description', 'Fournisseur', 'Montant', 'Catégorie', 'Sous-catégorie', 'Type'],
      allDailyHTMLRows
    )
  : '';

// Tableau par compte : masquer lignes où semaine = 0 ET mois = 0
const perAccountFiltered = perAccountTotals.filter(r => Number(r.weekly) !== 0 || Number(r.monthly) !== 0);
const part1PerAccountTitle = perAccountFiltered.length ? p('Dépenses cumulées par compte (semaine/mois ≠ 0)') : '';
const part1PerAccountRows = perAccountFiltered
  .sort((a,b)=> String(a.account).localeCompare(String(b.account), 'fr'))
  .map(r => [esc(r.account), esc(r.group), n0(r.weekly), n0(r.monthly)]);
const part1PerAccountTable = perAccountFiltered.length
  ? table(['Compte', 'Groupe', 'Total semaine', 'Total mois'], part1PerAccountRows)
  : '';

// ----- Partie 2 (HTML) -----
const part2DeltaTable = table(
  ['Précédent', 'Courant', 'Différence', 'Évolution (%)'],
  [[
    deltaView.previous_total == null ? '—' : n0(deltaView.previous_total),
    deltaView.current_total  == null ? '—' : n0(deltaView.current_total),
    deltaView.difference     == null ? '—' : n0(deltaView.difference),
    deltaView.percentage_change == null ? '—' : n0(deltaView.percentage_change)
  ]]
);

const part2ChangesRows = productChanges.map(ch => ([
  esc(ch.category ?? '—'),
  esc(ch.product  ?? ch.produit ?? ch.name ?? '—'),
  n0(ch.previous_quantity),
  n0(ch.current_quantity),
  n0(ch.quantity_change),
  n0(ch.previous_unit_price),
  n0(ch.current_unit_price),
  n0(ch.previous_total),
  n0(ch.current_total),
  n0(ch.total_change),
]));
const part2ChangesTable = table(
  ['Catégorie', 'Produit', 'Qté préc.', 'Qté cour.', 'Δ qté', 'PU préc.', 'PU cour.', 'Total préc.', 'Total cour.', 'Δ total'],
  part2ChangesRows.length ? part2ChangesRows : [['—','—','—','—','—','—','—','—','—','—']]
);

// ----- Partie 3 (HTML) -----
const pdvRows = Object.keys(byPdV).length
  ? Object.entries(byPdV).map(([k,v]) => [esc(k), n0(v)])
  : [['—', '—']];
const part3Table = table(
  ['Point de vente', 'Valeur cumulée'],
  pdvRows
);

// ----- Partie 4 (HTML) -----
const part4Rows = (livraisonRows.length ? livraisonRows : [{partner:'—',date:'—',amount:0,description:'—',status:'—',total_validated_deliveries:0,remaining_balance:0}])
  .map(r => [esc(r.partner), esc(r.date), n0(r.amount), esc(r.description), esc(r.status), n0(r.total_validated_deliveries), n0(r.remaining_balance)]);
const part4Table = table(
  ['Partenaire', 'Date', 'Montant', 'Description', 'Statut', 'Livraisons validées (total)', 'Solde restant'],
  part4Rows
);

// ----- Partie 5 (HTML) — PL uniquement -----
const part5PLTable = table(
  ['brutPL (valeur)', 'cash_bictorys', 'creances', 'stock_pv', 'écart stock vivant (mensuel)', 'cash_burn', 'livraisons_partenaire'],
  [[
    n0(brutPLObj.value),
    n0(brutComp.cash_bictorys),
    n0(brutComp.creances),
    n0(brutComp.stock_pv),
    n0(brutComp.ecart_stock_vivant_mensuel),
    n0(brutComp.cash_burn),
    n0(brutComp.livraisons_partenaire),
  ]]
);
const part5EstTable = table(
  ['estimatedProfitAndLoss (valeur)', 'estimated_fixed_charges'],
  [[
    n0(estPLObj.value),
    n0(fixedCharges),
  ]]
);

// ---------- SUBJECT / HTML / TEXT ----------
const subject = `Rapport quotidien – Dépenses & Stocks – ${dateSelected}`;

const html = `
  <div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.4;">
    ${h1('Partie 1 – Dépenses (Jour / Semaine / Mois)')}
    ${dateLine}
    ${part1Header}
    ${part1DailyTitle}${part1DailyTable}
    ${part1PerAccountTitle}${part1PerAccountTable}

    ${h1('Partie 2 – Stock vivant : Delta & Évolutions par produit')}
    ${part2DeltaTable}
    ${part2ChangesTable}

    ${h1('Partie 3 – Stock du soir (MATA)')}
    ${ssmLine}
    ${part3Table}

    ${h1('Partie 4 – Livraisons partenaires')}
    ${part4Table}

    ${h1('Partie 5 – Profit & Loss (global_metrics)')}
    <h3 style="margin:8px 0 4px 0;">5.1 – brutPL & estimatedProfitAndLoss</h3>
    ${part5PLTable}
    ${part5EstTable}
  </div>
`.trim();

// ---------- Version texte ----------
function asTextTable(headers, rows){
  const line = headers.join(' | ');
  const sep  = headers.map(h=>'—'.repeat(Math.max(3, h.length))).join('-|-');
  const body = rows.map(r => r.join(' | ')).join('\n');
  return [line, sep, body].join('\n');
}

const textSections = [];
textSections.push(`Partie 1 – Dépenses (Jour/Semaine/Mois) – Date: ${dateSelected}`);
textSections.push(`Totaux: Jour=${n0(totalDay)} | Semaine=${n0(totalWeek)} | Mois=${n0(totalMonth)}`);

// Dépenses du jour (≠ 0) — seulement si on a des lignes
if (allDailyTextRows.length) {
  textSections.push('');
  textSections.push(
    asTextTable(
      ['Compte','Description','Fournisseur','Montant','Catégorie','Sous-catégorie','Type'],
      allDailyTextRows
    )
  );
}

// Tableau par compte (filtré)
if (perAccountFiltered.length) {
  textSections.push('');
  textSections.push(
    asTextTable(
      ['Compte', 'Groupe', 'Total semaine', 'Total mois'],
      perAccountFiltered.map(r => [r.account, r.group, n0(r.weekly), n0(r.monthly)])
    )
  );
}

textSections.push('');
textSections.push('Partie 2 – Stock vivant : Delta & Évolutions');
textSections.push(
  `Delta: précédent=${deltaView.previous_total==null?'—':n0(deltaView.previous_total)} | courant=${deltaView.current_total==null?'—':n0(deltaView.current_total)} | diff=${deltaView.difference==null?'—':n0(deltaView.difference)} | évolution=${deltaView.percentage_change==null?'—':n0(deltaView.percentage_change)}%`
);
textSections.push(
  asTextTable(
    ['Catégorie','Produit','Qté préc.','Qté cour.','Δ qté','PU préc.','PU cour.','Total préc.','Total cour.','Δ total'],
    (productChanges.length ? productChanges : [{
      category:'—', product:'—', previous_quantity:0, current_quantity:0, quantity_change:0,
      previous_unit_price:0, current_unit_price:0, previous_total:0, current_total:0, total_change:0
    }]).map(ch => ([
      String(ch.category ?? '—'),
      String(ch.product  ?? ch.produit ?? ch.name ?? '—'),
      n0(ch.previous_quantity),
      n0(ch.current_quantity),
      n0(ch.quantity_change),
      n0(ch.previous_unit_price),
      n0(ch.current_unit_price),
      n0(ch.previous_total),
      n0(ch.current_total),
      n0(ch.total_change),
    ]))
  )
);

textSections.push('');
textSections.push('Partie 3 – Stock du soir (MATA)');
textSections.push(`Total stockSoirMata: ${ssmTotalValue==null?'—':n0(ssmTotalValue)}`);
textSections.push(
  asTextTable(
    ['Point de vente', 'Valeur cumulée'],
    (Object.keys(byPdV).length ? Object.entries(byPdV) : [['—', '—']]).map(([k,v]) => [k, n0(v)])
  )
);

textSections.push('');
textSections.push('Partie 4 – Livraisons partenaires');
textSections.push(
  asTextTable(
    ['Partenaire','Date','Montant','Description','Statut','Livraisons validées','Solde restant'],
    (livraisonRows.length ? livraisonRows : [{partner:'—',date:'—',amount:0,description:'—',status:'—',total_validated_deliveries:0,remaining_balance:0}])
      .map(r => [r.partner, r.date, n0(r.amount), r.description, r.status, n0(r.total_validated_deliveries), n0(r.remaining_balance)])
  )
);

textSections.push('');
textSections.push('Partie 5 – Profit & Loss (global_metrics)');
textSections.push(
  asTextTable(
    ['brutPL (valeur)', 'cash_bictorys', 'creances', 'stock_pv', 'écart stock vivant (mensuel)', 'cash_burn', 'livraisons_partenaire'],
    [[
      n0(brutPLObj.value),
      n0(brutComp.cash_bictorys),
      n0(brutComp.creances),
      n0(brutComp.stock_pv),
      n0(brutComp.ecart_stock_vivant_mensuel),
      n0(brutComp.cash_burn),
      n0(brutComp.livraisons_partenaire),
    ]]
  )
);
textSections.push(
  asTextTable(
    ['estimatedProfitAndLoss (valeur)', 'estimated_fixed_charges'],
    [[ n0(estPLObj.value), n0(fixedCharges) ]]
  )
);

const text = textSections.join('\n');

return [
  { json: { subject, html, text } }
];

// n8n Function node

function getDatesSkipSunday() {
  const fmt = d => {
    const dd = String(d.getDate()).padStart(2, '0');
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const yyyy = d.getFullYear();
    return `${dd}-${mm}-${yyyy}`;
  };

  const today = new Date();
  const c = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  c.setDate(c.getDate() - 1)
  const arr = [];
  while (arr.length < 3) {
    if (c.getDay() !== 0) arr.push(fmt(c)); // 0 = dimanche
    c.setDate(c.getDate() - 1);
  }

  return {
    today: fmt(new Date(today.getFullYear(), today.getMonth(), today.getDate())),
    yest: fmt(new Date(today.getFullYear(), today.getMonth(), today.getDate()-1))
  };
}

// Enrichir chaque item entrant (ou créer un item si aucun)
if (items.length === 0) {
  return [{ json: getDatesSkipSunday() }];
}

return items.map(item => {
  Object.assign(item.json, getDatesSkipSunday());
  return item;
});
